class Solution:
    def maxDepth(self, root):
        if root is None:
            return 0
        best = 0
        stack = [(root, 1)]
        while stack:
            node, d = stack.pop()
            if d > best:
                best = d
            for child in (node.children or []):
                stack.append((child, d + 1))
        return best

