var maxDepth = function(root) {
    if (!root) return 0;
    let depth = 0;
    let frontier = [root];
    while (frontier.length) {
        depth++;
        const next = [];
        for (const node of frontier) {
            for (const child of (node.children || [])) next.push(child);
        }
        frontier = next;
    }
    return depth;
};
